double Distance_slow = 0.25;         //判断距离低速
double Distance_high = 0.35;         //判断距离高速
double Distance_advance = 0.7;      //提前预判距离
uint32 Distance_INS = 27000;         //积分距离
double Distance_ = 0;

uint16 Distance_with_ban = 0;
uint16 dlla_out[5] = {10000,10000,10000,10000,10000};
uint16 dlla_fianl_out = 0;
uint32 INS_forward = 0;
uint8  INS_forward_flag = 0;
uint16 Distance_with = 400;

float angle_final;
float angle_OUT[4];                 //偏差缓冲器
double latitude = 0,longitude = 0;  //经纬度
double ins_x = 0,ins_y = 0;         //xy坐标
float Azimuth = 0;                  //方位角
float yaw = 0;                      //航向角
float Angle_Z_Final_zero = 0;
float variable_speed_servo =  25;   //变速角度

uint16 n =0;
uint8 m =0;

ins_struct ins;
uint8 ins_write = 0;       //惯性导航写入标志位
uint8 ins_read = 0;        //惯性导航读取标志位
