uint8 latitude1 [50] = {0};
uint8 latitude2 [50] = {0};
uint8 latitude3 [50] = {0};

uint8 longitude0 [50] = {0};
uint8 longitude1 [50] = {0};
uint8 longitude2 [50] = {0};
uint8 longitude3 [50] = {0};

