//-------------------------------------------------------------------------------------------------------------------
// 函数简介     解析导航数据
// 参数说明     uint8 mode:导航模式
// 返回参数     null
// 使用示例     data_get(car_flag);
// 备注信息
//-------------------------------------------------------------------------------------------------------------------
void data_get(uint8 mode)
{
    switch(mode)
    {
        case flag_RTK:
        {
            if(gnss_flag)
            {
                gnss_flag = 0;
                gnss_data_parse();                                                      //开始解析数据
                latitude = gnss.latitude;
                longitude = gnss.longitude;

                yaw = gnss.antenna_direction + calibration;
                if(yaw >=360)
                {
                    yaw -=360;
                }
            }
            break;
        }
        case flag_INS:
        {
            ins_x = ins.distance_x;
            ins_y = ins.distance_y;
            yaw = Angle_Z_Final - Angle_Z_Final_zero;
            if(yaw<0)
            {
                yaw += 360;
            }
            else if(yaw >= 360)
            {
                yaw -=360;
            }
            break;
        }
        default:break;
    }
}

//-------------------------------------------------------------------------------------------------------------------
// 函数简介     处理导航数据
// 参数说明     uint8 mode:导航模式
// 返回参数     null
// 使用示例     Angle_Deal(car_flag);
// 备注信息
//-------------------------------------------------------------------------------------------------------------------
void Angle_Deal(uint8 mode)
{
    switch(mode)
    {
        case flag_RTK:
        {
            Azimuth = get_two_points_azimuth(latitude, longitude, point_data[n][0], point_data[n][1]);//获取当前车子位置到下一个目标点的方位角，正北参考系
            Distance_Final = get_two_points_distance(latitude, longitude, point_data[n][0], point_data[n][1]);
            break;
        }
        case flag_INS:
        {
            Azimuth = ins_deviation(ins_x, ins_y, point_data[n][0], point_data[n][1]);
            Distance_Final = count_distence(ins_x, ins_y, point_data[n][0], point_data[n][1]);
            break;
        }
        default:break;
    }

    angle_final = Azimuth -yaw;//车头角度融合方位角计算偏差角
    if(angle_final>180)
    {
        angle_final-=360;
    }
    else if(angle_final<-180)
    {
        angle_final+=360;
    }
    angle_OUT[3]=angle_OUT[2];
    angle_OUT[2]=angle_OUT[1];
    angle_OUT[1]=angle_OUT[0];
    angle_OUT[0]=angle_final;
    servo = angle_final * 0.7 + angle_OUT[1] * 0.2 + angle_OUT[2] * 0.06 + angle_OUT[3] * 0.04;//偏差缓冲器

    //速度规划
    if(n == reduce[m])
    {
        if(mode == flag_INS)//惯性导航模式——摄像头修正目标方向
        {
            if(INS_forward_flag)
            {
                servo = 0;
            }
            else
            {
                servo = image_angle ;
            }
        }

        Velocity_limit = Velocity_limit_strike;//撞击速
        gpio_set_level(P14_3,1);
    }
    else
    {
        Velocity_Deal(servo,Distance_Final,point_data[n][0],point_data[n][1],point_data[n+1][0],point_data[n+1][1]);
        gpio_set_level(P14_3,0);
    }
    if(n == (reduce[m]+1))
        m++;

    if(Velocity_limit == Velocity_limit_strike)     //跳点距离的判断
    {
        Distance_ =  Distance_slow;
    }
    else
    {
        Distance_ = Distance_high;
    }

    if(Distance_Final < Distance_)
    {
        n++;
        if(n >= aim_point)
        {
            gpio_set_level(P14_3,1);
            stop_flag = 1;
        }
    }
}

void Velocity_Deal(float angle, double distance, double latitude_A, double longitude_A, double latitude_B, double longitude_B)//速度规划
{
    float prediction_angle = 0;

    if((distance <= Distance_advance) && (n < aim_point-1 ))//提前开启决策
    {
        prediction_angle = get_two_points_azimuth(latitude_A, longitude_A, latitude_B, longitude_B);
        prediction_angle -= yaw;
        prediction_angle = fabs(prediction_angle);
        if(reduce[m] == n+1)
        {
            Velocity_limit = Velocity_limit_servo;//弯道速度
        }
        else if(prediction_angle < variable_speed_servo)
        {
            Velocity_limit = Velocity_limit_zero;//直线速度
        }
        else
        {
            Velocity_limit = Velocity_limit_servo;//弯道速度
        }
    }
    //  else if(reduce[m] == 0)
    //  {
    //   if(fabs(Angle_X_Final - Mid_angle_X_zero) < 1.5 )
    //   {
    //       Velocity_limit = Velocity_limit_zero;
    //   }
    //   else
    //  {
    //      Velocity_limit = Velocity_limit_servo;
    //   }
    // }
    else if(fabs(servo) > variable_speed_servo)
    {
        Velocity_limit = Velocity_limit_servo;//弯道速度
    }

    else if(fabs(Angle_X_Final - Mid_angle_X_zero) < 2)
    {
        Velocity_limit = Velocity_limit_zero;//直线速度
    }
}

void caidian(uint8 mode)
{
    uint8 i = 0,j,k = 0;

    if(mode == flag_INS)
    {
        Angle_Z_Final_zero = yaw;
    }

    while (1)
    {

        key = key_scan();

        if(key == Mid_)
        {
            switch(mode)
            {
                case flag_RTK:
                {
                    point_data[i][0]= latitude;
                    point_data[i][1] = longitude;
                    break;
                }
                case flag_INS:
                {
                    point_data[i][0]= ins_x;
                    point_data[i][1] = ins_y;
                    break;
                }
                default:break;
            }
            i ++;
        }
        else if(key == Left_)
        {
            switch(mode)
            {
                case flag_RTK:
                {
                    point_data[i][0]= latitude;
                    point_data[i][1] = longitude;
                    break;
                }
                case flag_INS:
                {
                    point_data[i][0]= ins_x;
                    point_data[i][1] = ins_y;
                    break;
                }
                default:break;
            }
            i ++;
            reduce[k] = i-1;
            k++;
        }
        else if(key == Down_)
        {
            aim_point = i-1;
            reduce_point = k-1;
            break;
        }

        ips200_show_string(0,0,"score");

        ips200_show_int(100,0,i,2);
        ips200_show_int(130,0,k,2);
        if(i<12)
        {
            for(j = 0;j<12;j++)
            {
                ips200_show_float(0,Line*(j+1),point_data[j][0],2,6);
                ips200_show_float(120,Line*(j+1),point_data[j][1],3,6);
            }
        }
        else if((i >= 12) && (i < 24))
        {
            for(j = 0;j<12;j++)
            {
                ips200_show_float(0,Line*(j+1),point_data[j+12][0],2,6);
                ips200_show_float(120,Line*(j+1),point_data[j+12][1],3,6);
            }
        }
        else if((i >= 24) && (i < 36))
        {
            for(j = 0;j<12;j++)
            {
                ips200_show_float(0,Line*(j+1),point_data[j+24][0],2,6);
                ips200_show_float(120,Line*(j+1),point_data[j+24][1],3,6);
            }
        }
        else
        {
            for(j = 0;j<12;j++)
            {
                ips200_show_float(0,Line*(j+1),point_data[j+36][0],2,6);
                ips200_show_float(120,Line*(j+1),point_data[j+36][1],3,6);
            }
        }

        switch(mode)
        {
            case flag_RTK:
            {
                ips200_show_float(0,Line*14 ,yaw, 3, 1);
                ips200_show_float(0,Line*16 ,latitude, 3, 6);
                ips200_show_float(120, Line*16,longitude, 3, 6);
                break;
            }
            case flag_INS:
            {
                ips200_show_float(0,Line*14 ,yaw, 3, 1);
                ips200_show_float(0,Line*16 ,ins_x, 3, 6);
                ips200_show_float(120, Line*16,ins_y, 3, 6);
                break;
            }
            default:break;
        }
    }

    double_to_uint8();

    flash_buffer_clear();
    flash_erase_page(0,7);

    flash_union_buffer[0].uint8_type = aim_point;           //存目标点数

    for(int j=0;j<=aim_point;j++)
    {
        flash_union_buffer[j+1].uint8_type = latitude0[j];
    }

    for(int j=0;j<=aim_point;j++)
    {
        flash_union_buffer[j+1+aim_point*1].uint8_type = latitude1[j];
    }

    for(int j=0;j<=aim_point;j++)
    {
        flash_union_buffer[j+1+aim_point*2].uint8_type = latitude2[j];
    }

    for(int j=0;j<=aim_point;j++)
    {
        flash_union_buffer[j+1+aim_point*3].uint8_type = latitude3[j];
    }
    for(int j=0;j<=aim_point;j++)
    {
        flash_union_buffer[j+1+aim_point*4].uint8_type = longitude0[j];
    }

    for(int j=0;j<=aim_point;j++)
    {
        flash_union_buffer[j+1+aim_point*5].uint8_type = longitude1[j];
    }

    for(int j=0;j<=aim_point;j++)
    {
        flash_union_buffer[j+1+aim_point*6].uint8_type = longitude2[j];
    }

    for(int j=0;j<=aim_point;j++)
    {
        flash_union_buffer[j+1+aim_point*7].uint8_type = longitude3[j];
    }

    flash_union_buffer[2+aim_point*8].uint8_type = reduce_point;

    for(int j=0;j<=reduce_point;j++)
    {
        flash_union_buffer[j+3+aim_point*8].uint8_type = reduce[j];
    }

    flash_write_page_from_buffer (0, 7);

    ips200_clear();

}

