//-------------------------------------------------------------------------------------------------------------------
// 函数简介     惯性导航计算二维轨迹
// 参数说明     void
// 返回参数     null
// 使用示例     trajectory_calculation_2d(&ins);
// 备注信息
//-------------------------------------------------------------------------------------------------------------------
void trajectory_calculation_2d(ins_struct *ins)
{
    ins->Angle_deviation = yaw * AtR;
    ins->distance_x = ins->distance_x+cos(ins->Angle_deviation) * (ins->distance / 43600);
    ins->distance_y = ins->distance_y+sin(ins->Angle_deviation) * (ins->distance / 43600);
}

//-------------------------------------------------------------------------------------------------------------------
// 函数简介     惯性导航计算第一个点到第二个点的方位角
// 参数说明     double distance_x1,double distance_y1,double distance_x2,double distance_y2
// 返回参数     double
// 使用示例     ins_deviation(x,y);
// 备注信息     distance_x1，distance_y1  ：目标点位
//-------------------------------------------------------------------------------------------------------------------
double ins_deviation(double distance_x2,double distance_y2,double distance_x1,double distance_y1)
{
    double x,y;
    double angle;
    x=distance_x1-distance_x2;
    y=distance_y1-distance_y2;

    if(x>0&&y>0)  //第一象限
    {
        int left=0,right=4499,mid;
        if(y/x>=2864.788859)
        {
            angle=90;
        }else{
            while(1)
            {
                mid=left+(right-left)/2.0;
                if((y/x)>=tans[mid]&&(y/x)<tans[mid+1])
                {
                    angle=tan_angel[mid];
                    break;
                }else{
                    if(tans[mid]>(y/x)){
                        right=mid-1;
                    }else{
                        left=mid+1;
                    }
                }
            }
        }
    }
    if(x>0&&y<0)  //第二象限
    {
        int left=0,right=4499,mid;
        y=-y;
        if(x/y>=2864.788859)
        {
            angle=0;
        }else{
            while(1)
            {
                mid=left+(right-left)/2.0;
                if((x/y)>=tans[mid]&&(x/y)<tans[mid+1])
                {
                    angle=tan_angel[mid]+270;
                    break;
                }else{
                    if(tans[mid]>(x/y)){
                        right=mid-1;
                    }else{
                        left=mid+1;
                    }
                }
            }
        }
    }
    if(x<0&&y<0)  //第三象限
    {
        int left=0,right=4499,mid;
        x=-x;
        y=-y;
        if(y/x>=2864.788859)
        {
            angle=270;
        }else{
            while(1)
            {
                mid=left+(right-left)/2.0;
                if((y/x)>=tans[mid]&&(y/x)<tans[mid+1])
                {
                    angle=tan_angel[mid]+180;
                    break;
                }else{
                    if(tans[mid]>(y/x)){
                        right=mid-1;
                    }else{
                        left=mid+1;
                    }
                }
            }
        }
    }
    if(x<0&&y>0)  //第四象限
    {
        int left=0,right=4499,mid;
        x=-x;
        if(x/y>=2864.788859)
        {
            angle=180;
        }else{
            while(1)
            {
                mid=left+(right-left)/2.0;
                if((x/y)>=tans[mid]&&(x/y)<tans[mid+1])
                {
                    angle=tan_angel[mid]+90;
                    break;
                }else{
                    if(tans[mid]>(x/y)){
                        right=mid-1;
                    }else{
                        left=mid+1;
                    }
                }
            }
        }
    }
    if(x>0&&y==0)//x轴正半轴
    {
        angle=0;
    }
    if(x<0&&y==0)//x轴负半轴
    {
        angle=180;
    }
    if(x==0&&y>0)//y轴正半轴
    {
        angle=90;
    }
    if(x==0&&y<0)//y轴负半轴
    {
        angle=270;
    }
   return angle;
}

//-------------------------------------------------------------------------------------------------------------------
// 函数简介     惯性导航计算两点间距离
// 参数说明     double x1,double y1,double x2,double y2
// 返回参数     double distance
// 使用示例     count_distence(x1,y1,x2,y2);
// 备注信息
//-------------------------------------------------------------------------------------------------------------------
double count_distence(double x1,double y1,double x2,double y2)
{
    double distence;
    distence=sqrt((x2-x1)*(x2-x1)+(y2-y1)*(y2-y1));
    return distence;
}

//-------------------------------------------------------------------------------------------------------------------
// 函数简介     惯性导航初始化
// 参数说明     void
// 返回参数     null
// 使用示例     init_ins(&ins);
//-------------------------------------------------------------------------------------------------------------------
void init_ins(ins_struct *ins)
{
    ins->distance = 0;
    ins->Angle_deviation = yaw;
    ins->distance_x = 0;
    ins->distance_y = 0;
}


void double_to_uint8(void)
{
   for(uint8 i=0;i <= aim_point;i++)
   {
    if(car_flag == flag_RTK)
    {
        Disassembly_GPS(point_data[i][0],point_data[i][1],&x,&y);
    }
    else
    {
        Disassembly_INS(point_data[i][0],point_data[i][1],&x,&y);
    }
    u32_to_u8(&x,&latitude0[i],&latitude1[i],&latitude2[i],&latitude3[i]);
    u32_to_u8(&y,&longitude0[i],&longitude1[i],&longitude2[i],&longitude3[i]);
   }
}

void uint8_to_double(void)
{
    for(uint8 i=0;i <= aim_point;i++)
    {
     u8_to_u32(&x,&latitude0[i],&latitude1[i],&latitude2[i],&latitude3[i]);
     u8_to_u32(&y,&longitude0[i],&longitude1[i],&longitude2[i],&longitude3[i]);
     if(car_flag == flag_RTK)
     {
         Package_GPS(x,y,&point_data[i][0],&point_data[i][1]);
     }
     else
     {
         Package_INS(x,y,&point_data[i][0],&point_data[i][1]);
     }
    }
}
//-------------------------------------------------------------------------------------------------------------------
// 函数简介     将uint32类型数据拆分为4个uint8数据
// 参数说明     void
// 返回参数     null
// 使用示例     u32_to_u8(&data,&temp0,&temp1,&temp2,&temp3);
// 备注信息     temp0:1-8位，temp1:9-16位，temp2:17-24位，temp3:25-32位
//-------------------------------------------------------------------------------------------------------------------
void u32_to_u8(uint32 *data,uint8 *temp0,uint8 *temp1,uint8 *temp2,uint8 *temp3)
{
    *temp0 = *data;
    *temp1 = *data>>8;
    *temp2 = *data>>16;
    *temp3 = *data>>24;
}

//-------------------------------------------------------------------------------------------------------------------
// 函数简介     将4个uint8数据组合为1个uint32数据
// 参数说明     void
// 返回参数     null
// 使用示例     u8_to_u32(&data,&temp0,&temp1,&temp2,&temp3);
// 备注信息     temp0:1-8位，temp1:9-16位，temp2:17-24位，temp3:25-32位
//-------------------------------------------------------------------------------------------------------------------
void u8_to_u32(uint32 *data,uint8 *temp0,uint8 *temp1,uint8 *temp2,uint8 *temp3)
{
    uint32 l0,l1,l2,l3;
    l0=*temp0;
    l1=*temp1;
    l2=*temp2;
    l3=*temp3;
    *data = (l3<<24)|(l2<<16)|(l1<<8)|l0;
}

//-------------------------------------------------------------------------------------------------------------------
// 函数简介     GPS经纬度数据拆分
// 参数说明     void
// 返回参数     null
// 使用示例     Disassembly_GPS(latitude,longitude,&x,&y);
// 备注信息     latitude:纬度  longitude:经度   x:拆分后的纬度   y:拆分后的经度
//-------------------------------------------------------------------------------------------------------------------
void Disassembly_GPS(double latitude,double longitude,uint32 *x,uint32 *y)
{

    *x = latitude*1000000.0;
    *y = longitude*1000000.0;
}

void Disassembly_INS(double latitude,double longitude,uint32 *x,uint32 *y)
{

    *x = (latitude + 100.0)*1000000.0;
    *y = (longitude + 100.0)*1000000.0;
}

//-------------------------------------------------------------------------------------------------------------------
// 函数简介     GPS经纬度数据组合
// 参数说明     void
// 返回参数     null
// 使用示例     Package_GPS(latitude,longitude,&x,&y);
// 备注信息     latitude:纬度  longitude:经度   x:组合后的纬度   y:组合后的经度
//-------------------------------------------------------------------------------------------------------------------
void Package_GPS(uint32 latitude,uint32 longitude,double *x,double *y)
{
    *x  = (double)latitude/1000000.0;
    *y  = (double)longitude/1000000.0;
}

void Package_INS(uint32 latitude,uint32 longitude,double *x,double *y)
{
    *x  = (double)latitude/1000000.0 - 100.0;
    *y  = (double)longitude/1000000.0 - 100.0;
}
